class Solution:
    def stoneGame(self, piles):
        """
        :type piles: List[int]
        :rtype: bool
        """
        n = len(piles)
        memo = {}

        def dp(i, j):
            if i > j:
                return 0
            if (i, j) in memo:
                return memo[(i, j)]

            # Max score from this range
            result = max(piles[i] + (-dp(i + 1, j)),
                        piles[j] + (-dp(i, j - 1)))

            memo[(i, j)] = result
            return result

        return dp(0, n - 1) > 0
